ResponseDataConstant={RESPONSE_DATA="responseData",ERROR="error"}BaseViewModel=Object:extend()function BaseViewModel:new()BaseViewModel.super.new(self)end;function BaseViewModel:getLifecycleStatus()return self.lifecycleStatus end;function BaseViewModel:setLifecycleStatus(a)self.lifecycleStatus=a.lifecycleStatus;if self.lifecycleStatus==LifecycleStatus.ON_DEALLOC then self:onDealloc(a)elseif self.lifecycleStatus==LifecycleStatus.VIEW_DID_DESTROY then self:viewDidDestroy(a)elseif self.lifecycleStatus==LifecycleStatus.VIEW_DID_DISAPPEAR then self:viewDidDisappear(a)elseif self.lifecycleStatus==LifecycleStatus.VIEW_DID_APPEAR then self:viewDidAppear(a)elseif self.lifecycleStatus==LifecycleStatus.VIEW_DID_LOAD then self:viewDidLoad(a)end end;function BaseViewModel:viewDidLoad(a)end;function BaseViewModel:viewDidAppear(a)self:notifyResume()end;function BaseViewModel:viewDidDisappear(a)end;function BaseViewModel:onSizeChanged(a)end;function BaseViewModel:viewDidDestroy(a)end;function BaseViewModel:onDealloc(a)self:release(a)end;function BaseViewModel:notifyResume()for b,c in pairs(self)do if type(c)=="table"and c.isOKXLiveData then c:dispatchingValue()end end end;function BaseViewModel:release(a)end
